222→
223→    // Fetch replies for all top-level comments
224→    if (comments && comments.length > 0) {
225→        const commentIds = comments.map(c => c.id);
226→        const { data: replies, error: replyError } = await supabase
227→            .from('story_comments')
228→            .select(`*, users(id, name, image_url, username, badge)`)
229→            .in('parent_id', commentIds)
230→            .order('created_at', { ascending: true });
231→
232→        if (!replyError && replies) {
233→            const replyMap = {};
234→            replies.forEach(r => {
235→                if (!replyMap[r.parent_id]) replyMap[r.parent_id] = [];
236→                replyMap[r.parent_id].push(r);
237→            });
238→            comments.forEach(c => {
239→                c.replies = replyMap[c.id] || [];
240→            });
241→        }
242→    }
243→
244→    return comments || [];
245→};
